# Test that 'raise from None' suppresses __context__

print("Testing 'from None' exception chaining suppression:")
print("=" * 70)

try:
    try:
        raise RuntimeError("Original exception with credentials: postgresql://u:p@host/db")
    except RuntimeError as e:
        raise RuntimeError("New exception") from None
except RuntimeError as caught:
    print(f"Caught exception: {caught}")
    print(f"__cause__:           {caught.__cause__}")
    print(f"__context__:         {caught.__context__}")
    print(f"__suppress_context__: {caught.__suppress_context__}")
    print()
    if caught.__suppress_context__:
        print("✓ __suppress_context__ is True — context chain suppressed")
    else:
        print("❌ __suppress_context__ is False — context NOT suppressed")

EOF
